<script>
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

const W = 800;
const H = 600;
canvas.width = W;
canvas.height = H;

const startScreen = document.getElementById('startScreen');
const gameOverScreen = document.getElementById('gameOverScreen');
const winScreen = document.getElementById('winScreen');
const startBtn = document.getElementById('startBtn');
const restartBtn = document.getElementById('restartBtn');
const nextLevelBtn = document.getElementById('nextLevelBtn');

let gameState = 'start'; // start, playing, paused, gameover, win
let score = 0;
let highScore = parseInt(localStorage.getItem('breakoutHighScore')) || 0;
let lives = 3;
let level = 1;
let combo = 0;
let comboTimer = 0;
let shakeTimer = 0;
let shakeIntensity = 0;
let particles = [];
let powerUps = [];
let balls = [];

// Paddle
const paddle = {
    x: W / 2 - 60,
    y: H - 40,
    w: 120,
    h: 14,
    speed: 8,
    dx: 0,
    targetX: W / 2 - 60,
    color: '#00aaff'
};

// Ball template
function createBall(x, y, dx, dy) {
    return {
        x: x || W / 2,
        y: y || H - 55,
        radius: 8,
        speed: 5 + level * 0.3,
        dx: dx || (Math.random() > 0.5 ? 1 : -1) * (3 + Math.random()),
        dy: dy || -(4 + Math.random()),
        trail: [],
        active: true
    };
}

// Bricks
let bricks = [];
const brickRowCount = 6;
const brickColCount = 10;
const brickWidth = 68;
const brickHeight = 24;
const brickPadding = 4;
const brickOffsetTop = 60;
const brickOffsetLeft = (W - (brickColCount * (brickWidth + brickPadding) - brickPadding)) / 2;

const brickColors = [
    ['#ff4444', '#ff6666'], // red
    ['#ff8800', '#ffaa33'], // orange
    ['#ffcc00', '#ffdd44'], // yellow
    ['#44cc44', '#66ee66'], // green
    ['#4488ff', '#66aaff'], // blue
    ['#aa44ff', '#cc66ff'], // purple
];

const brickPoints = [7, 6, 5, 4, 3, 2];

// Power-up types
const POWERUP_TYPES = {
    WIDE: { color: '#00ff88', symbol: '⟷', effect: 'wide' },
    MULTI: { color: '#ff44ff', symbol: '×3', effect: 'multi' },
    SLOW: { color: '#44ffff', symbol: '▼', effect: 'slow' },
    LIFE: { color: '#ff4444', symbol: '♥', effect: 'life' },
    FIRE: { color: '#ff8800', symbol: '🔥', effect: 'fire' }
};

let activePowerUps = {};

function initBricks() {
    bricks = [];
    const rows = Math.min(brickRowCount + Math.floor(level / 2), 8);
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < brickColCount; c++) {
            let hp = 1;
            // Higher levels have tougher bricks
            if (level >= 3 && r < 2 && Math.random() < 0.3) hp = 2;
            if (level >= 5 && r < 1 && Math.random() < 0.2) hp = 3;

            // Some level patterns
            let visible = true;
            if (level === 2) {
                // Diamond pattern gap
                const centerC = brickColCount / 2 - 0.5;
                const centerR = rows / 2 - 0.5;
                if (Math.abs(c - centerC) + Math.abs(r - centerR) < 2.5) visible = false;
            }
            if (level === 4) {
                // Checkerboard
                if ((r + c) % 2 === 0 && r > 1) visible = false;
            }

            if (visible) {
                bricks.push({
                    x: brickOffsetLeft + c * (brickWidth + brickPadding),
                    y: brickOffsetTop + r * (brickHeight + brickPadding),
                    w: brickWidth,
                    h: brickHeight,
                    color: brickColors[r % brickColors.length][0],
                    colorLight: brickColors[r % brickColors.length][1],
                    points: brickPoints[r % brickPoints.length] * level,
                    hp: hp,
                    maxHp: hp,
                    alive: true,
                    row: r,
                    col: c
                });
            }
        }
    }
}

function resetBall() {
    balls = [createBall()];
    balls[0].dx = 0;
    balls[0].dy = 0;
    balls[0].stuck = true;
}

function launchBall() {
    if (balls.length > 0 && balls[0].stuck) {
        const angle = -Math.PI / 2 + (Math.random() - 0.5) * 0.5;
        balls[0].dx = Math.cos(angle) * balls[0].speed;
        balls[0].dy = Math.sin(angle) * balls[0].speed;
        balls[0].stuck = false;
    }
}

function init() {
    score = 0;
    lives = 3;
    level = 1;
    combo = 0;
    activePowerUps = {};
    particles = [];
    powerUps = [];
    paddle.w = 120;
    paddle.x = W / 2 - paddle.w / 2;
    initBricks();
    resetBall();
}

function nextLevel() {
    level++;
    combo = 0;
    activePowerUps = {};
    particles = [];
    powerUps = [];
    paddle.w = 120;
    paddle.x = W / 2 - paddle.w / 2;
    initBricks();
    resetBall();
}

// Input
let keys = {};
let mouseX = W / 2;
let useMouseControl = false;

document.addEventListener('keydown', (e) => {
    keys[e.key] = true;
    useMouseControl = false;
    if (e.key === ' ' && gameState === 'playing') {
        launchBall();
    }
});

document.addEventListener('keyup', (e) => {
    keys[e.key] = false;
});

canvas.addEventListener('mousemove', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    mouseX = (e.clientX - rect.left) * scaleX;
    useMouseControl = true;
});

canvas.addEventListener('click', () => {
    if (gameState === 'playing') {
        launchBall();
    }
});

startBtn.addEventListener('click', () => {
    startScreen.style.display = 'none';
    gameState = 'playing';
    init();
});

restartBtn.addEventListener('click', () => {
    gameOverScreen.style.display = 'none';
    gameState = 'playing';
    init();
});

nextLevelBtn.addEventListener('click', () => {
    winScreen.style.display = 'none';
    gameState = 'playing';
    nextLevel();
});

// Particles
function createParticles(x, y, color, count) {
    for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const speed = 1 + Math.random() * 4;
        particles.push({
            x: x,
            y: y,
            dx: Math.cos(angle) * speed,
            dy: Math.sin(angle) * speed,
            life: 1,
            decay: 0.02 + Math.random() * 0.03,
            size: 2 + Math.random() * 4,
            color: color
        });
    }
}

function createSparkle(x, y) {
    for (let i = 0; i < 5; i++) {
        particles.push({
            x: x + (Math.random() - 0.5) * 20,
            y: y + (Math.random() - 0.5) * 20,
            dx: (Math.random() - 0.5) * 2,
            dy: -1 - Math.random() * 2,
            life: 1,
            decay: 0.03,
            size: 1 + Math.random() * 2,
            color: '#ffffff'
        });
    }
}

function spawnPowerUp(x, y) {
    if (Math.random() > 0.15) return; // 15% chance
    const types = Object.values(POWERUP_TYPES);
    const type = types[Math.floor(Math.random() * types.length)];
    powerUps.push({
        x: x,
        y: y,
        w: 30,
        h: 16,
        dy: 2,
        type: type,
        glow: 0
    });
}

// Collision
function ballPaddleCollision(ball) {
    if (ball.dy > 0 &&
        ball.y + ball.radius > paddle.y &&
        ball.y - ball.radius < paddle.y + paddle.h &&
        ball.x > paddle.x - ball.radius &&
        ball.x < paddle.x + paddle.w + ball.radius) {

        // Calculate hit position (-1 to 1)
        const hitPos = (ball.x - (paddle.x + paddle.w / 2)) / (paddle.w / 2);
        const maxAngle = Math.PI / 3; // 60 degrees
        const angle = hitPos * maxAngle;

        const speed = Math.sqrt(ball.dx * ball.dx + ball.dy * ball.dy);
        ball.dx = Math.sin(angle) * speed;
        ball.dy = -Math.cos(angle) * speed;

        ball.y = paddle.y - ball.radius;

        createSparkle(ball.x, ball.y);
        combo = 0;
    }
}

function ballBrickCollision(ball) {
    for (let brick of bricks) {
        if (!brick.alive) continue;

        // AABB collision
        const closestX = Math.max(brick.x, Math.min(ball.x, brick.x + brick.w));
        const closestY = Math.max(brick.y, Math.min(ball.y, brick.y + brick.h));
        const distX = ball.x - closestX;
        const distY = ball.y - closestY;
        const dist = Math.sqrt(distX * distX + distY * distY);

        if (dist < ball.radius) {
            brick.hp--;

            if (brick.hp <= 0) {
                brick.alive = false;
                combo++;
                comboTimer = 120;
                const comboMultiplier = Math.min(combo, 10);
                const points = brick.points * comboMultiplier;
                score += points;

                createParticles(brick.x + brick.w / 2, brick.y + brick.h / 2, brick.color, 12);
                shakeTimer = 5;
                shakeIntensity = 3;

                spawnPowerUp(brick.x + brick.w / 2, brick.y + brick.h / 2);

                // Floating score text
                particles.push({
                    x: brick.x + brick.w / 2,
                    y: brick.y + brick.h / 2,
                    dx: 0,
                    dy: -1,
                    life: 1,
                    decay: 0.015,
                    size: 0,
                    color: '#ffcc00',
                    text: `+${points}`,
                    isText: true
                });
            } else {
                createParticles(closestX, closestY, '#ffffff', 5);
                shakeTimer = 3;
                shakeIntensity = 2;
            }

            // Fire ball goes through bricks
            if (activePowerUps.fire && activePowerUps.fire > 0) {
                continue;
            }

            // Determine bounce direction
            const overlapX = ball.radius - Math.abs(distX);
            const overlapY = ball.radius - Math.abs(distY);

            if (overlapX < overlapY) {
                ball.dx = -ball.dx;
                ball.x += distX > 0 ? overlapX : -overlapX;
            } else {
                ball.dy = -ball.dy;
                ball.y += distY > 0 ? overlapY : -overlapY;
            }

            return; // Only one brick collision per frame
        }
    }
}

function applyPowerUp(type) {
    switch (type.effect) {
        case 'wide':
            paddle.w = Math.min(200, paddle.w + 40);
            activePowerUps.wide = 600;
            break;
        case 'multi':
            const newBalls = [];
            for (let ball of balls) {
                if (!ball.stuck) {
                    newBalls.push(createBall(ball.x, ball.y, ball.dx * 0.8 + 2, ball.dy));
                    newBalls.push(createBall(ball.x, ball.y, ball.dx * 0.8 - 2, ball.dy));
                }
            }
            balls = balls.concat(newBalls);
            break;
        case 'slow':
            for (let ball of balls) {
                ball.dx *= 0.7;
                ball.dy *= 0.7;
            }
            break;
        case 'life':
            lives = Math.min(lives + 1, 5);
            break;
        case 'fire':
            activePowerUps.fire = 300;
            break;
    }
}

// Update
function update() {
    if (gameState !== 'playing') return;

    // Paddle movement
    if (useMouseControl) {
        paddle.targetX = mouseX - paddle.w / 2;
    } else {
        if (keys['ArrowLeft'] || keys['a']) paddle.targetX = paddle.x - paddle.speed;
        if (keys['ArrowRight'] || keys['d']) paddle.targetX = paddle.x + paddle.speed;
    }

    paddle.targetX = Math.max(0, Math.min(W - paddle.w, paddle.targetX));
    paddle.x += (paddle.targetX - paddle.x) * 0.3;

    // Update balls
    for (let ball of balls) {
        if (ball.stuck) {
            ball.x = paddle.x + paddle.w / 2;
            ball.y = paddle.y - ball.radius - 1;
            continue;
        }

        // Trail
        ball.trail.push({ x: ball.x, y: ball.y });
        if (ball.trail.length > 8) ball.trail.shift();

        ball.x += ball.dx;
        ball.y += ball.dy;

        // Wall collision
        if (ball.x - ball.radius < 0) {
            ball.x = ball.radius;
            ball.dx = Math.abs(ball.dx);
        }
        if (ball.x + ball.radius > W) {
            ball.x = W - ball.radius;
            ball.dx = -Math.abs(ball.dx);
        }
        if (ball.y - ball.radius < 0) {
            ball.y = ball.radius;
            ball.dy = Math.abs(ball.dy);
        }

        // Bottom - ball lost
        if (ball.y - ball.radius > H) {
            ball.active = false;
        }

        ballPaddleCollision(ball);
        ballBrickCollision(ball);

        // Speed cap
        const speed = Math.sqrt(ball.dx * ball.dx + ball.dy * ball.dy);
        const maxSpeed = 10;
        const minSpeed = 3;
        if (speed > maxSpeed) {
            ball.dx = (ball.dx / speed) * maxSpeed;
            ball.dy = (ball.dy / speed) * maxSpeed;
        }
        if (speed < minSpeed && !ball.stuck) {
            ball.dx = (ball.dx / speed) * minSpeed;
            ball.dy = (ball.dy / speed) * minSpeed;
        }

        // Ensure ball isn't going purely horizontal
        if (Math.abs(ball.dy) < 1 && !ball.stuck) {
            ball.dy = ball.dy < 0 ? -1.5 : 1.5;
        }
    }

    // Remove inactive balls
    balls = balls.filter(b => b.active);

    // All balls lost
    if (balls.length === 0) {
        lives--;
        combo = 0;
        activePowerUps = {};
        paddle.w = 120;

        if (lives <= 0) {
            gameState = 'gameover';
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('breakoutHighScore', highScore);
            }
            document.getElementById('finalScore').textContent = `得分: ${score}`;
            document.getElementById('highScoreText').textContent = `最高分: ${highScore}`;
            gameOverScreen.style.display = 'flex';
            shakeTimer = 20;
            shakeIntensity = 8;
        } else {
            resetBall();
        }
    }

    // Power-ups
    for (let pu of powerUps) {
        pu.y += pu.dy;
        pu.glow = (pu.glow + 0.1) % (Math.PI * 2);

        // Paddle collision
        if (pu.y + pu.h > paddle.y && pu.y < paddle.y + paddle.h &&
            pu.x + pu.w / 2 > paddle.x && pu.x - pu.w / 2 < paddle.x + paddle.w) {
            applyPowerUp(pu.type);
            createParticles(pu.x, pu.y, pu.type.color, 10);
            pu.collected = true;
        }

        if (pu.y > H + 20) pu.collected = true;
    }
    powerUps = powerUps.filter(p => !p.collected);

    // Particles
    for (let p of particles) {
        p.x += p.dx;
        p.y += p.dy;
        p.life -= p.decay;
        if (!p.isText) {
            p.dy += 0.05; // gravity
        }
    }
    particles = particles.filter(p => p.life > 0);

    // Power-up timers
    for (let key in activePowerUps) {
        activePowerUps[key]--;
        if (activePowerUps[key] <= 0) {
            delete activePowerUps[key];
            if (key === 'wide') paddle.w = 120;
        }
    }

    // Combo timer
    if (comboTimer > 0) comboTimer--;
    else combo = 0;

    // Shake timer
    if (shakeTimer > 0) shakeTimer--;

    // Win check
    if (bricks.every(b => !b.alive)) {
        gameState = 'win';
        if (score > highScore) {
            highScore = score;
            localStorage.setItem('breakoutHighScore', highScore);
        }
        document.getElementById('winScore').textContent = `得分: ${score}`;
        document.getElementById('winHighScore').textContent = `最高分: ${highScore}`;
        winScreen.style.display = 'flex';
    }
}

// Draw
function draw() {
    ctx.save();

    // Screen shake
    if (shakeTimer > 0) {
        const sx = (Math.random() - 0.5) * shakeIntensity;
        const sy = (Math.random() - 0.5) * shakeIntensity;
        ctx.translate(sx, sy);
    }

    // Background
    const grad = ctx.createLinearGradient(0, 0, 0, H);
    grad.addColorStop(0, '#0a0a2e');
    grad.addColorStop(1, '#1a1a4e');
    ctx.fillStyle = grad;
    ctx.fillRect(-10, -10, W + 20, H + 20);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x < W; x += 40) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, H);
        ctx.stroke();
    }
    for (let y = 0; y < H; y += 40) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(W, y);
        ctx.stroke();
    }

    // Bricks
    for (let brick of bricks) {
        if (!brick.alive) continue;

        const g = ctx.createLinearGradient(brick.x, brick.y, brick.x, brick.y + brick.h);
        g.addColorStop(0, brick.colorLight);
        g.addColorStop(1, brick.color);

        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.roundRect(brick.x, brick.y, brick.w, brick.h, 3);
        ctx.fill();

        // Shine
        ctx.fillStyle = 'rgba(255,255,255,0.2)';
        ctx.fillRect(brick.x + 2, brick.y + 2, brick.w - 4, brick.h / 3);

        // HP indicator for tough bricks
        if (brick.maxHp > 1) {
            ctx.fillStyle = 'rgba(255,255,255,0.8)';
            ctx.font = 'bold 12px Arial';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(brick.hp, brick.x + brick.w / 2, brick.y + brick.h / 2);
        }

        // Glow
        ctx.shadowColor = brick.color;
        ctx.shadowBlur = 5;
        ctx.strokeStyle = brick.color;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.roundRect(brick.x, brick.y, brick.w, brick.h, 3);
        ctx.stroke();
        ctx.shadowBlur = 0;
    }

    // Power-ups
    for (let pu of powerUps) {
        const glowSize = 3 + Math.sin(pu.glow) * 2;
        ctx.shadowColor = pu.type.color;
        ctx.shadowBlur = 10 + glowSize;
        ctx.fillStyle = pu.type.color;
        ctx.beginPath();
        ctx.roundRect(pu.x - pu.w / 2, pu.y - pu.h / 2, pu.w, pu.h, 5);
        ctx.fill();
        ctx.shadowBlur = 0;

        ctx.fillStyle = '#fff';
        ctx.font = 'bold 11px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(pu.type.symbol, pu.x, pu.y);
    }

    // Ball trail and ball
    for (let ball of balls) {
        // Trail
        for (let i = 0; i < ball.trail.length; i++) {
            const t = ball.trail[i];
            const alpha = (i / ball.trail.length) * 0.4;
            const size = ball.radius * (i / ball.trail.length) * 0.8;

            let trailColor = `rgba(255, 255, 255, ${alpha})`;
            if (activePowerUps.fire) {
                trailColor = `rgba(255, ${100 + i * 15}, 0, ${alpha})`;
            }
            ctx.fillStyle = trailColor;
            ctx.beginPath();
            ctx.arc(t.x, t.y, size, 0, Math.PI * 2);
            ctx.fill();
        }

        // Ball glow
        if (activePowerUps.fire) {
            ctx.shadowColor = '#ff4400';
            ctx.shadowBlur = 20;
        } else {
            ctx.shadowColor = '#ffffff';
            ctx.shadowBlur = 15;
        }

        // Ball
        const ballGrad = ctx.createRadialGradient(
            ball.x - 2, ball.y - 2, 0,
            ball.x, ball.y, ball.radius
        );
        if (activePowerUps.fire) {
            ballGrad.addColorStop(0, '#ffff00');
            ballGrad.addColorStop(0.5, '#ff8800');
            ballGrad.addColorStop(1, '#ff4400');
        } else {
            ballGrad.addColorStop(0, '#ffffff');
            ballGrad.addColorStop(0.5, '#aaddff');
            ballGrad.addColorStop(1, '#4488ff');
        }
        ctx.fillStyle = ballGrad;
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;
    }

    // Paddle
    const paddleGrad = ctx.createLinearGradient(paddle.x, paddle.y, paddle.x, paddle.y + paddle.h);
