    for (let brick of bricks) {
        if (!brick.alive) continue;

        const g = ctx.createLinearGradient(brick.x, brick.y, brick.x, brick.y + brick.h);
        g.addColorStop(0, brick.colorLight);
        g.addColorStop(1, brick.color);

        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.roundRect(brick.x, brick.y, brick.w, brick.h, 3);
        ctx.fill();

        // Shine
        ctx.fillStyle = 'rgba(255,255,255,0.2)';
        ctx.fillRect(brick.x + 2, brick.y + 2, brick.w - 4, brick.h / 3);

        // HP indicator for tough bricks
        if (brick.maxHp > 1) {
            ctx.fillStyle = 'rgba(255,255,255,0.8)';
            ctx.font = 'bold 12px Arial';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(brick.hp, brick.x + brick.w / 2, brick.y + brick.h / 2);
        }

        // Glow
        ctx.shadowColor = brick.color;
        ctx.shadowBlur = 5;
        ctx.strokeStyle = brick.color;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.roundRect(brick.x, brick.y, brick.w, brick.h, 3);
        ctx.stroke();
        ctx.shadowBlur = 0;
    }

    // Power-ups
    for (let pu of powerUps) {
        const glowSize = 3 + Math.sin(pu.glow) * 2;
        ctx.shadowColor = pu.type.color;
        ctx.shadowBlur = 10 + glowSize;
        ctx.fillStyle = pu.type.color;
        ctx.beginPath();
        ctx.roundRect(pu.x - pu.w / 2, pu.y - pu.h / 2, pu.w, pu.h, 5);
        ctx.fill();
        ctx.shadowBlur = 0;

        ctx.fillStyle = '#fff';
        ctx.font = 'bold 11px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(pu.type.symbol, pu.x, pu.y);
    }

    // Ball trail and ball
    for (let ball of balls) {
        // Trail
        for (let i = 0; i < ball.trail.length; i++) {
            const t = ball.trail[i];
            const alpha = (i / ball.trail.length) * 0.4;
            const size = ball.radius * (i / ball.trail.length) * 0.8;

            let trailColor = `rgba(255, 255, 255, ${alpha})`;
            if (activePowerUps.fire) {
                trailColor = `rgba(255, ${100 + i * 15}, 0, ${alpha})`;
            }
            ctx.fillStyle = trailColor;
            ctx.beginPath();
            ctx.arc(t.x, t.y, size, 0, Math.PI * 2);
            ctx.fill();
        }

        // Ball glow
        if (activePowerUps.fire) {
            ctx.shadowColor = '#ff4400';
            ctx.shadowBlur = 20;
        } else {
            ctx.shadowColor = '#ffffff';
            ctx.shadowBlur = 15;
        }

        // Ball
        const ballGrad = ctx.createRadialGradient(
            ball.x - 2, ball.y - 2, 0,
            ball.x, ball.y, ball.radius
        );
        if (activePowerUps.fire) {
            ballGrad.addColorStop(0, '#ffff00');
            ballGrad.addColorStop(0.5, '#ff8800');
            ballGrad.addColorStop(1, '#ff4400');
        } else {
            ballGrad.addColorStop(0, '#ffffff');
            ballGrad.addColorStop(0.5, '#aaddff');
            ballGrad.addColorStop(1, '#4488ff');
        }
        ctx.fillStyle = ballGrad;
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;
    }

    // Paddle
    const paddleGrad = ctx.createLinearGradient(paddle.x, paddle.y, paddle.x, paddle.y + paddle.h);
    if (activePowerUps.wide) {
        paddleGrad.addColorStop(0, '#00ff88');
        paddleGrad.addColorStop(1, '#008844');
    } else {
        paddleGrad.addColorStop(0, '#44bbff');
        paddleGrad.addColorStop(1, '#0066cc');
    }

    ctx.shadowColor = activePowerUps.wide ? '#00ff88' : '#00aaff';
    ctx.shadowBlur = 15;
    ctx.fillStyle = paddleGrad;
    ctx.beginPath();
    ctx.roundRect(paddle.x, paddle.y, paddle.w, paddle.h, 7);
    ctx.fill();

    // Paddle shine
    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.beginPath();
    ctx.roundRect(paddle.x + 4, paddle.y + 2, paddle.w - 8, paddle.h / 2 - 1, 4);
    ctx.fill();
    ctx.shadowBlur = 0;

    // Particles
    for (let p of particles) {
        if (p.isText) {
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.font = 'bold 16px Arial';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(p.text, p.x, p.y);
            ctx.globalAlpha = 1;
        } else {
            ctx.globalAlpha = p.life;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1;
        }
    }

    // HUD
    // Score
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 20px Arial';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    ctx.fillText(`得分: ${score}`, 15, 10);

    // Level
    ctx.textAlign = 'center';
    ctx.fillText(`第 ${level} 关`, W / 2, 10);

    // Lives
    ctx.textAlign = 'right';
    let livesText = '';
    for (let i = 0; i < lives; i++) livesText += '❤️ ';
    ctx.font = '18px Arial';
    ctx.fillText(livesText, W - 15, 12);

    // Combo
    if (combo > 1 && comboTimer > 0) {
        ctx.textAlign = 'center';
        ctx.font = `bold ${18 + combo}px Arial`;
        const comboAlpha = Math.min(comboTimer / 30, 1);
        ctx.fillStyle = `rgba(255, 200, 0, ${comboAlpha})`;
        ctx.fillText(`${combo}x 连击!`, W / 2, 38);
    }

    // Active power-up indicators
    let puY = 50;
    for (let key in activePowerUps) {
        const remaining = activePowerUps[key];
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.font = '12px Arial';
        ctx.textAlign = 'left';
        ctx.fillText(`${key}: ${Math.ceil(remaining / 60)}s`, 15, puY);
        puY += 18;
    }

    // Launch hint
    if (balls.length > 0 && balls[0].stuck && gameState === 'playing') {
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        ctx.font = '16px Arial';
        ctx.textAlign = 'center';
        ctx.fillText('点击鼠标或按空格键发射', W / 2, H - 80);
    }

    ctx.restore();
}

// Game loop
function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

// Show start screen
startScreen.style.display = 'flex';
gameLoop();
</script>
